def mapLeafIntInt(xs: FBase, f: Traversers.IntToIntFn): FBase = xs match {
  case e: Empty => Empty.INSTANCE
  case o: IntOne => new IntOne(f.apply(o.elem))
  case leaf: IntArr => {
    val a = leaf.arr
    val n = a.length
    val out = new Array[Int](n)
    var i = 0
    while (i < n) {
      out(i) = f.apply(a(i))
      i += 1
    }
    new IntArr(out, n)
  } case _ => {
    val n = xs.length
    val out = new Array[Int](n)
    val k = Traversers.buildFwdIntInt(xs, out, 0, f)
    { val _l = k; if (_l == 0) Empty.INSTANCE else if (_l == 1) new IntOne(out(0)) else new IntArr(out, _l) }
  }
}

