  case leaf: IntArr => {
    val a = leaf.arr
    val n = a.length
    val out = new Array[Object](n)
    var i = 0
    while (i < n) {
      out(i) = f.apply(a(i)).asInstanceOf[Object]
      i += 1
    }
    new RefArr(out, n)
  } case _ => {
    val n = xs.length
    val out = new Array[Object](n)
    val k = Traversers.buildFwdIntRef[RO](xs, out, 0, f)
    { val _l = k; if (_l == 0) Empty.INSTANCE else if (_l == 1) new RefOne(out(0)) else new RefArr(out, _l) }
  }
}

